    total_mask := 1 << n1
    dp := make([][][]int64, total_mask)
    for mask := 0; mask < total_mask; mask++ {
        dp[mask] = make([][]int64, n1)
        for u := 0; u < n1; u++ {
            dp[mask][u] = make([]int64, n1)
            for v := 0; v < n1; v++ {
                dp[mask][u][v] = -1
            }
        }
    }
    for u := 0; u < n1; u++ {
        mask := 1 << u
        dp[mask][u][u] = 1
    }
    for _, e := range edges {
        u := int(e[0])
        v := int(e[1])
        if label[u] == label[v] {
            mask := (1 << u) | (1 << v)
            dp[mask][u][v] = 2
            dp[mask][v][u] = 2
        }
    }
    ans := int64(1)
